import{q as c,u as d,j as e,bh as l}from"./vendor-react-D1Zcby_M.js";import{V as m,B as p,C as u,F as g,G as x,J as h}from"./App-CU7nnTC1.js";import"./vendor-i18n-AOdgFpXS.js";import"./vendor-editor-B1vH4T8i.js";import"./vendor-utils-CPmww8iS.js";import"./index-JPLxJ_bu.js";import"./vendor-supabase-C7oYX5mF.js";import"./config-DxqXxpjb.js";const z=()=>{const{t:y,i18n:i}=c();d();const s=m("/"),n=i.language,t={zh:{title:"隐私政策",lastUpdated:"最后更新：2026年4月",sections:[{title:"1. 信息收集",content:"我们在您注册和使用服务时收集您主动提供的个人信息（姓名、邮箱、电话、餐厅信息等）。同时我们会自动收集技术与访问数据，包括：访问的页面路径、错误信息、浏览器类型、匿名化后的 IP 地址（去除最后一段）、近似地理位置（国家/城市）、停留时长。"},{title:"2. 信息使用与法律依据",content:"我们处理您的数据基于以下依据：(a)『合法利益』——保障平台安全、诊断错误与 404 页面问题（即使您拒绝分析 Cookie 也会进行）；(b)『您的同意』——分析访问行为、优化产品、记录地理位置与停留时长；(c)『合同履行』——账户登录、订单、订阅。"},{title:"3. 信息共享",content:"我们不会出售您的个人信息。我们仅在以下情况下共享信息：与必要的服务提供商合作（Supabase、Mapbox、Google）、遵守法律要求、保护我们的权利与安全。"},{title:"4. 数据安全与保留期限",content:"我们采取适当的技术措施保护您的数据。访问日志保留 30 天后自动删除；账户信息在您的账户活跃期间保留；订单与发票数据按法律要求保留 5-10 年。"},{title:"5. 您的权利（GDPR / 个保法）",content:"您有权：访问、更正、删除您的个人信息；导出数据副本；反对或限制处理；撤回同意。请发送邮件至 comercial@xiaoxiong.pt 申请，我们将在 30 天内回复。请在邮件中注明您的注册邮箱与具体诉求。"},{title:"6. Cookie 与追踪",content:"我们使用两类 Cookie：(a)『必要 Cookie』——登录会话、错误日志、安全防护，无法关闭；(b)『分析 Cookie』——页面访问追踪、停留时长、地理位置，仅在您同意后启用。您可以随时通过浏览器设置或清除本站数据来撤回同意，下次访问时同意横幅会再次出现。"},{title:"7. 联系我们",content:"数据保护相关问题或行使您的权利，请联系：comercial@xiaoxiong.pt"}]},en:{title:"Privacy Policy",lastUpdated:"Last Updated: April 2026",sections:[{title:"1. Information Collection",content:"We collect personal information you provide when registering and using our services (name, email, phone, restaurant info). We also automatically collect technical and visit data: visited page paths, error messages, browser type, anonymized IP address (last octet removed), approximate location (country/city), and time spent on pages."},{title:"2. Use of Information & Legal Basis",content:"We process your data on the following bases: (a) Legitimate Interest — platform security, error and 404 diagnostics (collected even if you refuse analytics cookies); (b) Your Consent — analytics tracking, product optimization, recording approximate location and dwell time; (c) Contract Performance — account login, orders, subscriptions."},{title:"3. Information Sharing",content:"We do not sell your personal information. We share information only with essential service providers (Supabase, Mapbox, Google), to comply with legal requirements, or to protect our rights and security."},{title:"4. Data Security & Retention",content:"We implement appropriate technical measures to protect your data. Visit logs are automatically deleted after 30 days; account information is retained while your account is active; order and invoice data is kept for 5–10 years as required by law."},{title:"5. Your Rights (GDPR)",content:"You have the right to: access, correct, or delete your personal information; export a copy of your data; object to or restrict processing; withdraw consent. Email comercial@xiaoxiong.pt to exercise these rights — we will respond within 30 days. Please include your registered email and specific request."},{title:"6. Cookies & Tracking",content:"We use two categories of cookies: (a) Essential cookies — login session, error logs, security; cannot be disabled; (b) Analytics cookies — page visit tracking, dwell time, location; only enabled with your consent. You may withdraw consent any time by clearing this site's data in your browser; the consent banner will reappear on your next visit."},{title:"7. Contact Us",content:"For data protection questions or to exercise your rights, contact: comercial@xiaoxiong.pt"}]},pt:{title:"Política de Privacidade",lastUpdated:"Última Atualização: Abril 2026",sections:[{title:"1. Recolha de Informações",content:"Recolhemos informações pessoais que fornece ao registar-se e utilizar os nossos serviços (nome, e-mail, telefone, informações do restaurante). Também recolhemos automaticamente dados técnicos e de visita: caminhos das páginas visitadas, mensagens de erro, tipo de navegador, endereço IP anonimizado (último octeto removido), localização aproximada (país/cidade) e tempo de permanência."},{title:"2. Utilização e Base Legal",content:"Tratamos os seus dados com base em: (a) Interesse Legítimo — segurança da plataforma, diagnóstico de erros e 404 (recolhido mesmo se recusar cookies analíticos); (b) Seu Consentimento — análise de utilização, otimização do produto, registo de localização e tempo de permanência; (c) Execução de Contrato — login, pedidos, subscrições."},{title:"3. Partilha de Informações",content:"Não vendemos as suas informações pessoais. Partilhamos apenas com prestadores de serviços essenciais (Supabase, Mapbox, Google), para cumprir requisitos legais ou proteger os nossos direitos e segurança."},{title:"4. Segurança e Retenção de Dados",content:"Implementamos medidas técnicas adequadas. Os logs de visita são eliminados automaticamente após 30 dias; as informações da conta são mantidas enquanto a conta estiver ativa; dados de encomendas e faturas são mantidos 5–10 anos conforme exigido por lei."},{title:"5. Os Seus Direitos (RGPD)",content:"Tem o direito de: aceder, corrigir ou eliminar as suas informações; exportar uma cópia dos seus dados; opor-se ou limitar o tratamento; retirar o consentimento. Envie e-mail para comercial@xiaoxiong.pt — responderemos em 30 dias. Indique o seu e-mail registado e o pedido específico."},{title:"6. Cookies e Rastreamento",content:"Utilizamos duas categorias de cookies: (a) Essenciais — sessão de login, logs de erro, segurança; não podem ser desativados; (b) Analíticos — rastreamento de páginas, tempo de permanência, localização; apenas com o seu consentimento. Pode retirar o consentimento limpando os dados deste site no navegador; o banner de consentimento reaparecerá na próxima visita."},{title:"7. Contacte-nos",content:"Para questões de proteção de dados ou exercer os seus direitos, contacte: comercial@xiaoxiong.pt"}]}},o=t[n]||t.en;return e.jsx("div",{className:"min-h-screen pt-4 pb-12 px-4 bg-secondary/20",children:e.jsxs("div",{className:"container mx-auto max-w-4xl",children:[e.jsx(p,{variant:"ghost",size:"icon",onClick:s,className:"h-10 w-10 mb-4 rounded-md bg-background shadow-sm border border-border/50",children:e.jsx(l,{className:"h-5 w-5"})}),e.jsxs(u,{children:[e.jsxs(g,{children:[e.jsx(x,{className:"text-3xl font-bold",children:o.title}),e.jsx("p",{className:"text-muted-foreground",children:o.lastUpdated})]}),e.jsx(h,{className:"space-y-6",children:o.sections.map((a,r)=>e.jsxs("div",{children:[e.jsx("h2",{className:"text-xl font-semibold mb-2",children:a.title}),e.jsx("p",{className:"text-muted-foreground leading-relaxed",children:a.content})]},r))})]})]})})};export{z as default};
